  m_m	dq 1.0, 0.0, 0.0, 0.0
; m_Outer
; m_Inner
; None_m
; Outer_None
; Outer_L
; Outer_R
; Outer_m
; Outer_Outer
; Outer_Inner
; None_Outer
; Inner_None
; Inner_L
; Inner_R
; Inner_m
; Inner_Outer
; Inner_Inner
; None_Inner
EDGE_REGIONS ENDS

